import React, { useState } from 'react';

/**
 * High-Quality, Remixable EXP Level Card Component.
 *
 * Displays current level and progress toward the next level.
 * Fully customizable via props for colors, starting stats, and EXP curve.
 *
 * @param {number} initialLevel - Starting level. Defaults to 1.
 * @param {number} initialExp - Starting EXP points. Defaults to 0.
 * @param {number} expIncrement - How much the EXP requirement increases per level. Defaults to 50.
 * @param {string} baseColorClass - Tailwind gradient classes (e.g., 'from-blue-600 to-indigo-900').
 * @param {string} highlightColorClass - Tailwind border/shadow classes (e.g., 'border-blue-500').
 */
export default function ExpLevelCard({
  initialLevel = 1,
  initialExp = 0,
  expIncrement = 50,
  baseColorClass = 'from-red-600 to-rose-900',
  highlightColorClass = 'border-red-500',
}) {
  const [level, setLevel] = useState(initialLevel);
  const [exp, setExp] = useState(initialExp);

  // Compute EXP needed based on current level
  const expToNextLevel = 100 + (level - 1) * expIncrement;

  // Handle gaining random EXP on click
  const handleGainExp = () => {
    const gained = Math.floor(Math.random() * 50) + 10;
    const totalExp = exp + gained;

    if (totalExp >= expToNextLevel) {
      const nextLevel = level + 1;
      setLevel(nextLevel);
      setExp(totalExp - expToNextLevel);
    } else {
      setExp(totalExp);
    }
  };

  // Progress bar width
  const progressWidth = `${(exp / expToNextLevel) * 100}%`;

  return (
    <div
      className={`
        relative 
        w-28 
        h-20 
        rounded-lg 
        overflow-hidden 
        bg-gradient-to-br ${baseColorClass} 
        border-2 ${highlightColorClass} 
        shadow-xl 
        hover-tilt 
        cursor-pointer 
        transition-all 
        duration-300
      `}
      onClick={handleGainExp}
    >
      <div className="absolute inset-0 flex flex-col items-center justify-center">
        <span className="text-xs font-bold text-white tracking-widest text-shadow-lg">
          LEVEL {level}
        </span>
        <span className="text-xl font-bold text-white tracking-widest text-shadow-lg">
          EXP
        </span>
      </div>

      <div className="absolute bottom-2 left-2 right-2 h-1.5 bg-white/30 rounded-full overflow-hidden">
        <div
          className="h-full bg-white rounded-full transition-all duration-300 ease-out"
          style={{ width: progressWidth }}
        />
      </div>
    </div>
  );
}
